-- Matthew 28: Resurrection and the Great Commission
-- Chapter metadata, verses, word studies, cross references

-- 1. Chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 28,
  'Matthew closes his Gospel with the decisive event on which the entire Christian proclamation rests: the bodily resurrection of Jesus Christ from the dead. As the first day of the week dawns, Mary Magdalene and the other Mary come to the sealed and guarded tomb, where a great earthquake accompanies the descent of an angel whose appearance is as lightning. The angel rolls back the stone not to let Jesus out but to let witnesses in, and he announces, "He is not here: for he is risen, as he said." The women depart with fear and great joy, and the risen Lord meets them on the way, receiving their worship and commissioning them to tell his "brethren" to meet him in Galilee. Meanwhile, a second narrative unfolds in Jerusalem: the guards report the truth to the chief priests, who bribe them to spread a lie that the disciples stole the body, a cover-up that Matthew notes persisted "until this day." The Gospel reaches its climax on a mountain in Galilee where the eleven disciples see Jesus, worship him, and receive the Great Commission. Vested with "all authority in heaven and in earth," Jesus issues a universal mandate: to disciple all nations, baptizing them in the triune name of the Father, and of the Son, and of the Holy Ghost, and teaching them to observe everything he has commanded. The Gospel that began with "Emmanuel, God with us" (1:23) ends with the sovereign promise of that presence extended through the age: "Lo, I am with you alway, even unto the end of the world." Thus the resurrection is not an epilogue but the hinge on which the new covenant mission turns, the inauguration of the worldwide reign of the risen Messiah through his disciple-making church.',
  'The Risen King and the Universal Commission',
  'ἐγείρω',
  'to raise, wake, arise (from death)',
  '["The empty tomb and the angelic announcement (vv.1-8)", "The risen Christ appears to the women (vv.9-10)", "The priests bribe the guards to spread a lie (vv.11-15)", "The Great Commission on the mountain in Galilee (vv.16-20)"]'::jsonb
FROM books b WHERE b.name = 'Matthew'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

-- 2. Verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'In the end of the sabbath, as it began to dawn toward the first day of the week, came Mary Magdalene and the other Mary to see the sepulchre.',
   'Ὀψὲ δὲ σαββάτων, τῇ ἐπιφωσκούσῃ εἰς μίαν σαββάτων, ἦλθεν Μαρία ἡ Μαγδαληνὴ καὶ ἡ ἄλλη Μαρία θεωρῆσαι τὸν τάφον.',
   'Opse de sabbatōn, tē epiphōskousē eis mian sabbatōn, ēlthen Maria hē Magdalēnē kai hē allē Maria theōrēsai ton taphon.',
   'Matthew''s temporal marker is carefully constructed. "Opse sabbatōn" ("late on the sabbath") coupled with "epiphōskousē eis mian sabbatōn" ("as it was dawning toward the first day of the week") places the women''s visit at daybreak Sunday. Jewish days ended at sunset, so the sabbath had legally ended Saturday evening, but the women wait until dawn for travel. "The other Mary" (cf. 27:56, 61) is Mary the mother of James and Joses. Their purpose is to "see" (theōrēsai, to look attentively upon) — a vigil of love, not yet expectation of resurrection.',
   'The women disciples'' devotion becomes the occasion of the first resurrection announcement: God honors loving persistence with revelation, setting the pattern that the gospel comes first to those who seek Christ even in sorrow.'),
  (2, 'And, behold, there was a great earthquake: for the angel of the Lord descended from heaven, and came and rolled back the stone from the door, and sat upon it.',
   'Καὶ ἰδοὺ σεισμὸς ἐγένετο μέγας· ἄγγελος γὰρ κυρίου καταβὰς ἐξ οὐρανοῦ καὶ προσελθὼν ἀπεκύλισεν τὸν λίθον καὶ ἐκάθητο ἐπάνω αὐτοῦ.',
   'Kai idou seismos egeneto megas; angelos gar kyriou katabas ex ouranou kai proselthōn apekylisen ton lithon kai ekathēto epanō autou.',
   '"Seismos megas" ("great earthquake") forms an inclusio with the earthquake at the crucifixion (27:51): creation convulses at both the death and resurrection of its Maker. The angel rolls back the stone not to release Jesus — he had already risen (v.6) — but to reveal the empty tomb to witnesses. The angel sitting "upon" the stone is a posture of triumph over the sealed tomb, its guards, and death itself.',
   'God providentially arranges physical signs to confirm spiritual realities. The earthquake, the descending angel, and the rolled stone are not decorative miracles but evidences provided to establish faith in the resurrection before any human witness arrives.'),
  (3, 'His countenance was like lightning, and his raiment white as snow:',
   'ἦν δὲ ἡ εἰδέα αὐτοῦ ὡς ἀστραπὴ καὶ τὸ ἔνδυμα αὐτοῦ λευκὸν ὡς χιών.',
   'Ēn de hē eidea autou hōs astrapē kai to endyma autou leukon hōs chiōn.',
   'The description echoes Daniel 10:6 and Jesus'' own transfiguration (17:2). "Astrapē" ("lightning") signifies divine glory in visible flash; "leukos hōs chiōn" ("white as snow") recalls the Ancient of Days (Dan 7:9). Matthew frames the angel as a herald robed in heavenly splendor, marking the cosmic significance of the moment: heaven''s messenger visibly presides over the tomb of its King.',
   'Heavenly glory attends the resurrection, demonstrating that the raising of Christ is not a private event but a cosmic disclosure involving the full heavenly order. The angelic splendor testifies that the new age of divine glory has broken into human history.'),
  (4, 'And for fear of him the keepers did shake, and became as dead men.',
   'ἀπὸ δὲ τοῦ φόβου αὐτοῦ ἐσείσθησαν οἱ τηροῦντες καὶ ἐγενήθησαν ὡς νεκροί.',
   'Apo de tou phobou autou eseisthēsan hoi tērountes kai egenēthēsan hōs nekroi.',
   'Ironic inversion: the Roman guards stationed to prevent resurrection become "as dead men" before the sign of life. "Eseisthēsan" ("were shaken") uses the same root as "seismos" in v.2 — the earth quakes, the guards quake, while the resurrection stands firm. Matthew''s readers, many of whom had seen Roman power crush Jerusalem in AD 70, would recognize the theological point: earthly power collapses before heaven''s messenger.',
   'Sinful human opposition cannot withstand divine intervention. The same power that guards could not resist will topple every worldly system arrayed against the risen Christ; the consummation of his kingdom is already proleptically enacted at the tomb.'),
  (5, 'And the angel answered and said unto the women, Fear not ye: for I know that ye seek Jesus, which was crucified.',
   'ἀποκριθεὶς δὲ ὁ ἄγγελος εἶπεν ταῖς γυναιξίν· μὴ φοβεῖσθε ὑμεῖς, οἶδα γὰρ ὅτι Ἰησοῦν τὸν ἐσταυρωμένον ζητεῖτε·',
   'Apokritheis de ho angelos eipen tais gynaixin; mē phobeisthe hymeis, oida gar hoti Iēsoun ton estaurōmenon zēteite.',
   '"Hymeis" ("you," emphatic) contrasts the women with the guards: where enemies tremble in terror, disciples are told not to fear. "Ton estaurōmenon" ("the crucified one") is a perfect passive participle — the cross remains the permanent identifier of the risen Lord; the resurrection does not erase Calvary but vindicates it. The angel addresses them with pastoral care: seeking Jesus is rightly ordered love.',
   'The risen Christ is forever the crucified Christ; the wounds and the glory cohere. Believers encounter not a post-crucifixion Jesus who has transcended the cross, but the slain-and-risen Lamb whose resurrection confirms his atoning work.'),
  (6, 'He is not here: for he is risen, as he said. Come, see the place where the Lord lay.',
   'οὐκ ἔστιν ὧδε, ἠγέρθη γὰρ καθὼς εἶπεν· δεῦτε ἴδετε τὸν τόπον ὅπου ἔκειτο.',
   'Ouk estin hōde, ēgerthē gar kathōs eipen; deute idete ton topon hopou ekeito.',
   '"Ēgerthē" ("he has been raised") is a divine passive aorist: God the Father raised him (cf. Acts 2:24, Rom 6:4). "Kathōs eipen" ("just as he said") underscores the fulfillment of Jesus'' repeated passion-resurrection predictions (16:21, 17:23, 20:19). The invitation "deute idete" ("come, see") offers empirical verification — the Christian gospel welcomes investigation of the empty tomb.',
   'The resurrection is the Father''s public vindication of the Son''s self-attestation. Jesus rose "as he said," establishing that his words are the very words of God, and that the whole of Christian hope is grounded in a verifiable historical event, not a devotional metaphor.'),
  (7, 'And go quickly, and tell his disciples that he is risen from the dead; and, behold, he goeth before you into Galilee; there shall ye see him: lo, I have told you.',
   'καὶ ταχὺ πορευθεῖσαι εἴπατε τοῖς μαθηταῖς αὐτοῦ ὅτι ἠγέρθη ἀπὸ τῶν νεκρῶν, καὶ ἰδοὺ προάγει ὑμᾶς εἰς τὴν Γαλιλαίαν· ἐκεῖ αὐτὸν ὄψεσθε· ἰδοὺ εἶπον ὑμῖν.',
   'Kai tachy poreutheisai eipate tois mathētais autou hoti ēgerthē apo tōn nekrōn, kai idou proagei hymas eis tēn Galilaian; ekei auton opsesthe; idou eipon hymin.',
   '"Proagei" ("he goes before") picks up Jesus'' prediction at 26:32, reinstating the shepherd-sheep imagery of Mark 14:28 and Zechariah 13:7. Galilee — the despised region where Jesus began his ministry (4:15-16) — becomes the launch point for the global mission, embodying the reversal of Jewish expectation that Zion alone is the center of redemptive history.',
   'The resurrection commissions its witnesses before it consoles them. The gospel is entrusted to those who have seen: women, specifically, who in first-century Judaism could not testify legally — a detail that argues for the narrative''s historical reliability, since no Jewish author would have invented it.'),
  (8, 'And they departed quickly from the sepulchre with fear and great joy; and did run to bring his disciples word.',
   'καὶ ἀπελθοῦσαι ταχὺ ἀπὸ τοῦ μνημείου μετὰ φόβου καὶ χαρᾶς μεγάλης ἔδραμον ἀπαγγεῖλαι τοῖς μαθηταῖς αὐτοῦ.',
   'Kai apelthousai tachy apo tou mnēmeiou meta phobou kai charas megalēs edramon apangeilai tois mathētais autou.',
   'The paradoxical pairing "phobou kai charas megalēs" ("fear and great joy") captures the proper posture of Easter faith: reverent awe before divine action blended with exultation at divine grace. "Edramon" ("they ran") is a verb of evangelistic haste, anticipating the missionary urgency of the Great Commission.',
   'Christian proclamation is born from personal encounter with the risen Christ and inherits both awe and joy. Fear without joy becomes dread; joy without fear becomes presumption; together they constitute worship.'),
  (9, 'And as they went to tell his disciples, behold, Jesus met them, saying, All hail. And they came and held him by the feet, and worshipped him.',
   'καὶ ἰδοὺ Ἰησοῦς ὑπήντησεν αὐταῖς λέγων· χαίρετε. αἱ δὲ προσελθοῦσαι ἐκράτησαν αὐτοῦ τοὺς πόδας καὶ προσεκύνησαν αὐτῷ.',
   'Kai idou Iēsous hypēntēsen autais legōn; chairete. Hai de proselthousai ekratēsan autou tous podas kai prosekynēsan autō.',
   '"Chairete" ("rejoice, greetings") was an ordinary Greek salutation but here bears its full force of resurrection joy. "Ekratēsan autou tous podas" ("they took hold of his feet") emphasizes the bodily reality of the resurrection — Jesus is not a phantom but touchable flesh. "Prosekynēsan" ("worshipped") is the verb reserved for deity; the women render to the risen Jesus the worship owed to God alone, and he accepts it.',
   'The risen Christ receives divine worship, confirming his identity as God incarnate. The bodily tangibility of the encounter safeguards the resurrection from docetic reduction: the same body that was crucified is now glorified and worshipped.'),
  (10, 'Then said Jesus unto them, Be not afraid: go tell my brethren that they go into Galilee, and there shall they see me.',
   'τότε λέγει αὐταῖς ὁ Ἰησοῦς· μὴ φοβεῖσθε· ὑπάγετε ἀπαγγείλατε τοῖς ἀδελφοῖς μου ἵνα ἀπέλθωσιν εἰς τὴν Γαλιλαίαν, κἀκεῖ με ὄψονται.',
   'Tote legei autais ho Iēsous; mē phobeisthe; hypagete apangeilate tois adelphois mou hina apelthōsin eis tēn Galilaian, kakei me opsontai.',
   'Jesus calls the disciples "tous adelphous mou" ("my brethren") — despite their recent abandonment, he reaffirms familial solidarity (cf. Heb 2:11-12, Ps 22:22). His first instruction to them post-resurrection is not rebuke but reunion. The repetition of the Galilee rendezvous (vv.7, 10) underscores its importance for the climactic Great Commission.',
   'The resurrection inaugurates a new kinship in which the risen Son gathers fellow-sons into the Father''s family. Grace precedes commission: Jesus restores before he deploys, turning failed disciples into apostolic brothers.'),
  (11, 'Now when they were going, behold, some of the watch came into the city, and shewed unto the chief priests all the things that were done.',
   'Πορευομένων δὲ αὐτῶν ἰδού τινες τῆς κουστωδίας ἐλθόντες εἰς τὴν πόλιν ἀπήγγειλαν τοῖς ἀρχιερεῦσιν ἅπαντα τὰ γενόμενα.',
   'Poreuomenōn de autōn idou tines tēs koustōdias elthontes eis tēn polin apēngeilan tois archiereusin hapanta ta genomena.',
   '"Koustōdia" is a Latin loanword (custodia) for the Roman guard detail Pilate assigned (27:65-66). Matthew places two contrasting missions side by side: the women proclaiming resurrection to the disciples, and the guards reporting resurrection to the chief priests. Both groups are eyewitnesses; their responses diverge along lines of prior allegiance.',
   'The same factual evidence provokes faith in some and hardened resistance in others; the decisive factor is not the clarity of the sign but the condition of the heart.'),
  (12, 'And when they were assembled with the elders, and had taken counsel, they gave large money unto the soldiers,',
   'καὶ συναχθέντες μετὰ τῶν πρεσβυτέρων συμβούλιόν τε λαβόντες ἀργύρια ἱκανὰ ἔδωκαν τοῖς στρατιώταις',
   'Kai synachthentes meta tōn presbyterōn symboulion te labontes argyria hikana edōkan tois stratiōtais',
   '"Argyria hikana" ("enough silver pieces," i.e. a substantial bribe) echoes the thirty pieces of silver paid to Judas (26:15) — the leaders who bought the betrayal now buy the cover-up. "Symboulion" ("council") is the same word used for their earlier plots to kill Jesus (12:14, 22:15, 27:1, 27:7), underscoring continuity in their opposition.',
   'Religious authority divorced from truth will finance lies to protect its position. Matthew exposes the depravity of institutional self-preservation: the priests who rent their clothes at blasphemy now purchase perjury to silence the glory of God.'),
  (13, 'Saying, Say ye, His disciples came by night, and stole him away while we slept.',
   'λέγοντες· εἴπατε ὅτι οἱ μαθηταὶ αὐτοῦ νυκτὸς ἐλθόντες ἔκλεψαν αὐτὸν ἡμῶν κοιμωμένων.',
   'Legontes; eipate hoti hoi mathētai autou nyktos elthontes eklepsan auton hēmōn koimōmenōn.',
   'The fabricated story is internally incoherent: sleeping guards cannot testify to what happened while they slept. Roman discipline for sleeping on duty was capital punishment (Acts 12:19), which is precisely why v.14 promises to protect them from Pilate. The narrative preserves the earliest Jewish polemic against the resurrection (still attested in Justin Martyr, Dial. 108), and Matthew records it to refute it.',
   'Unbelief often resorts to explanations that require greater credulity than faith itself. The "stolen body" hypothesis has been rehearsed in every generation, but it could never account for the transformation of disciples willing to die for what they would have known was a fraud.'),
  (14, 'And if this come to the governor''s ears, we will persuade him, and secure you.',
   'καὶ ἐὰν ἀκουσθῇ τοῦτο ἐπὶ τοῦ ἡγεμόνος, ἡμεῖς πείσομεν αὐτὸν καὶ ὑμᾶς ἀμερίμνους ποιήσομεν.',
   'Kai ean akousthē touto epi tou hēgemonos, hēmeis peisomen auton kai hymas amerimnous poiēsomen.',
   '"Peisomen" ("we will persuade") — probably a euphemism for further bribery of Pilate, whose venality is attested by Josephus and Philo. "Amerimnous" ("free from anxiety, out of trouble") promises legal protection from the Roman capital penalty for sleeping on watch. The priests treat truth as a commodity negotiable by silver.',
   'Corrupted religion will collaborate with corrupted civil power to suppress the truth of God. Yet no human council can "secure" anyone from the reality of a risen Christ; the priests'' assurance is hollow against the coming Judge.'),
  (15, 'So they took the money, and did as they were taught: and this saying is commonly reported among the Jews until this day.',
   'οἱ δὲ λαβόντες τὰ ἀργύρια ἐποίησαν ὡς ἐδιδάχθησαν. καὶ διεφημίσθη ὁ λόγος οὗτος παρὰ Ἰουδαίοις μέχρι τῆς σήμερον ἡμέρας.',
   'Hoi de labontes ta argyria epoiēsan hōs edidachthēsan. Kai diephēmisthē ho logos houtos para Ioudaiois mechri tēs sēmeron hēmeras.',
   '"Mechri tēs sēmeron hēmeras" ("until this day") marks the time of Matthew''s composition (c. AD 60-80) and implies the stolen-body rumor remained live polemic in the synagogue. Matthew''s appeal is apologetic: he explains the counter-narrative his Jewish-Christian readers encountered and refutes it by exposing its mercenary origin.',
   'The resurrection is the most controverted and best-attested event of history; the church must always be ready to engage the alternative explanations circulating in each generation with both evidence and patience.'),
  (16, 'Then the eleven disciples went away into Galilee, into a mountain where Jesus had appointed them.',
   'Οἱ δὲ ἕνδεκα μαθηταὶ ἐπορεύθησαν εἰς τὴν Γαλιλαίαν εἰς τὸ ὄρος οὗ ἐτάξατο αὐτοῖς ὁ Ἰησοῦς.',
   'Hoi de hendeka mathētai eporeuthēsan eis tēn Galilaian eis to oros hou etaxato autois ho Iēsous.',
   '"Hendeka" ("eleven") — Judas'' absence is a silent sermon on apostasy. "To oros" ("the mountain") is a Matthean motif: the mountain of temptation (4:8), the Sermon on the Mount (5:1), the transfiguration (17:1), and now the commissioning. The unidentified mountain in Galilee becomes a new Sinai, where the risen King issues the covenant commands of his global kingdom.',
   'God gathers his scattered witnesses at the place he has appointed. Obedience to the resurrected Christ begins with simple compliance: the eleven went to the mountain he named, before they received any commission.'),
  (17, 'And when they saw him, they worshipped him: but some doubted.',
   'καὶ ἰδόντες αὐτὸν προσεκύνησαν, οἱ δὲ ἐδίστασαν.',
   'Kai idontes auton prosekynēsan, hoi de edistasan.',
   '"Prosekynēsan" ("they worshipped") registers the same divine worship offered in v.9. "Edistasan" ("doubted, hesitated") is the same verb used of Peter sinking in 14:31; it denotes wavering rather than unbelief. Matthew''s candid acknowledgment of lingering doubt among the worshippers is another mark of historical integrity — an invented resurrection would not leave its eleven heroes partly uncertain.',
   'True worship and remaining doubt can coexist in the same disciple. Christ commissions not the flawlessly confident but the worshipping and wavering, demonstrating that saving faith is the movement of doubters toward the feet of their Lord.'),
  (18, 'And Jesus came and spake unto them, saying, All power is given unto me in heaven and in earth.',
   'καὶ προσελθὼν ὁ Ἰησοῦς ἐλάλησεν αὐτοῖς λέγων· ἐδόθη μοι πᾶσα ἐξουσία ἐν οὐρανῷ καὶ ἐπὶ τῆς γῆς.',
   'Kai proselthōn ho Iēsous elalēsen autois legōn; edothē moi pasa exousia en ouranō kai epi tēs gēs.',
   '"Exousia" ("authority") is far broader than "power"; it is delegated right to rule. "Edothē" ("has been given") is a divine passive pointing to the Father''s bestowal, fulfilling Daniel 7:13-14 where the Son of Man receives universal dominion. "Pasa" ("all") is exhaustive — no realm lies outside his sovereignty. Satan offered partial kingdoms in 4:8-9; the Father has now granted the total cosmos to the obedient Son.',
   'The Great Commission rests on the greater coronation. Because Christ possesses comprehensive authority over angels, nations, demons, and nature, his church''s mission is guaranteed to succeed. Mission without this christological foundation degenerates into moralism or activism.'),
  (19, 'Go ye therefore, and teach all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Ghost:',
   'πορευθέντες οὖν μαθητεύσατε πάντα τὰ ἔθνη, βαπτίζοντες αὐτοὺς εἰς τὸ ὄνομα τοῦ πατρὸς καὶ τοῦ υἱοῦ καὶ τοῦ ἁγίου πνεύματος,',
   'Poreuthentes oun mathēteusate panta ta ethnē, baptizontes autous eis to onoma tou patros kai tou huiou kai tou hagiou pneumatos,',
   'The main verb is "mathēteusate" ("make disciples"), an imperative, modified by three participles: "poreuthentes" ("going"), "baptizontes" ("baptizing"), "didaskontes" ("teaching"). "Panta ta ethnē" ("all the nations/Gentiles") breaks the earlier restriction to Israel (10:5-6); the Messiah''s reign is coextensive with creation. "Eis to onoma" (singular "name") governing three divine persons is the fullest Trinitarian formula in the Synoptics — one divine Name, three equal persons.',
   'The Trinity is not a later church construction but the very grammar of baptism mandated by the risen Christ. Every believer is immersed into the one Name shared by Father, Son, and Spirit, establishing trinitarian identity as foundational to Christian existence and mission.'),
  (20, 'Teaching them to observe all things whatsoever I have commanded you: and, lo, I am with you alway, even unto the end of the world. Amen.',
   'διδάσκοντες αὐτοὺς τηρεῖν πάντα ὅσα ἐνετειλάμην ὑμῖν· καὶ ἰδοὺ ἐγὼ μεθ'' ὑμῶν εἰμι πάσας τὰς ἡμέρας ἕως τῆς συντελείας τοῦ αἰῶνος.',
   'Didaskontes autous tērein panta hosa eneteilamēn hymin; kai idou egō meth'' hymōn eimi pasas tas hēmeras heōs tēs synteleias tou aiōnos.',
   '"Didaskontes… tērein" ("teaching to observe") demands not mere information transfer but formation in obedience. "Panta hosa eneteilamēn" ("all that I commanded") sets Jesus'' teaching — the Sermon on the Mount, the parables, the kingdom ethics — as the canonical curriculum of discipleship. The closing promise "egō meth'' hymōn eimi" ("I am with you") forms an inclusio with the opening name Emmanuel (1:23), and "heōs tēs synteleias tou aiōnos" ("until the end of the age") stretches that presence across the entire church age. Many manuscripts omit the final "Amēn."',
   'The resurrected Christ is universally present to his missionary people until the consummation. The Great Commission is therefore not a burden imposed on absent disciples but a partnership with the omnipresent King, who guarantees his presence, power, and perseverance to his church unto the end of the age.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Matthew' AND c.chapter_number = 28
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

-- 3. Word studies
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἐπιφωσκούσῃ', 'epiphōskousē', 'G2020', 'Present active participle of epiphōskō, "to dawn, grow light." Used only here and Luke 23:54; signals the decisive first-day-of-the-week timing that anchors Christian Sunday worship.', 1),
  (1, 'μίαν σαββάτων', 'mian sabbatōn', 'G3391/G4521', 'Hebrew-flavored Greek idiom, "first of the sabbaths," i.e. the first day of the week. Sets the historical foundation for the Christian observance of the Lord''s Day.', 2),
  (2, 'σεισμὸς', 'seismos', 'G4578', 'Earthquake, shaking. Occurs at both the crucifixion (27:51) and the resurrection, marking cosmic acts of divine intervention.', 3),
  (2, 'ἀπεκύλισεν', 'apekylisen', 'G617', 'Aorist of apokyliō, "to roll away." The stone is removed not for Jesus to exit but for witnesses to enter and see; underscores the demonstrative, public character of the resurrection.', 4),
  (3, 'ἀστραπὴ', 'astrapē', 'G796', 'Lightning, flash. Used of divine glory and the Son of Man''s parousia (24:27); the angel''s appearance situates him within the theophanic tradition.', 5),
  (4, 'τηροῦντες', 'tērountes', 'G5083', 'Present participle of tēreō, "to guard, keep watch." The verb of vigilant observation — the guards fail at the very task their role demands.', 6),
  (5, 'ἐσταυρωμένον', 'estaurōmenon', 'G4717', 'Perfect passive participle of stauroō, "to crucify." The perfect tense emphasizes the abiding identity: the risen Lord remains the one who has been and ever is the crucified.', 7),
  (6, 'ἠγέρθη', 'ēgerthē', 'G1453', 'Aorist passive of egeirō, "to raise up." Divine passive; the Father is the implicit subject. The central claim of the chapter and of apostolic preaching.', 8),
  (6, 'ἔκειτο', 'ekeito', 'G2749', 'Imperfect of keimai, "to lie." Matthew invites the reader to inspect the empty space; the physical evidence is there to be examined.', 9),
  (7, 'προάγει', 'proagei', 'G4254', 'Present active of proagō, "to go before, lead." Shepherd language (cf. 26:32); the risen Christ pastors his scattered flock toward new pasture in Galilee.', 10),
  (8, 'ἔδραμον', 'edramon', 'G5143', 'Aorist of trechō, "to run." Evangelistic haste: receipt of resurrection news compels proclamation at a run.', 11),
  (9, 'χαίρετε', 'chairete', 'G5463', 'Imperative of chairō, "rejoice, greetings." A standard salutation that here bears full resurrection joy; Jesus'' first word post-resurrection is "Rejoice."', 12),
  (9, 'προσεκύνησαν', 'prosekynēsan', 'G4352', 'Aorist of proskyneō, "to worship, prostrate before." Used for deity; the women offer — and Jesus accepts — divine homage, confirming his godhood.', 13),
  (10, 'ἀδελφοῖς', 'adelphois', 'G80', 'Brothers, brethren. After their desertion, Jesus calls the disciples "my brethren"; resurrection creates a new familial bond through the risen Firstborn.', 14),
  (11, 'κουστωδίας', 'koustōdias', 'G2892', 'Latin loanword custodia, "guard, watch." Refers to the Roman detail assigned to seal the tomb; its helplessness before resurrection is the point.', 15),
  (12, 'ἀργύρια ἱκανὰ', 'argyria hikana', 'G694/G2425', 'Substantial silver pieces; a large bribe. Echoes the thirty pieces paid Judas — silver finances both the betrayal and the cover-up.', 16),
  (12, 'συμβούλιον', 'symboulion', 'G4824', 'Council, consultation. Matthew''s fingerprint word for the Sanhedrin''s conspiratorial meetings (12:14; 22:15; 27:1,7).', 17),
  (14, 'ἀμερίμνους', 'amerimnous', 'G275', 'Free from care, out of trouble. Alpha-privative of merimna (anxiety). The priests promise what only Christ can truly give — and they do so with a lie.', 18),
  (15, 'διεφημίσθη', 'diephēmisthē', 'G1310', 'Aorist passive of diaphēmizō, "to spread abroad, publish widely." The stolen-body story circulated publicly; Matthew documents its ongoing polemic.', 19),
  (16, 'ἐτάξατο', 'etaxato', 'G5021', 'Aorist middle of tassō, "to appoint, arrange." Jesus appointed a specific mountain; the commission unfolds at the appointed place.', 20),
  (17, 'ἐδίστασαν', 'edistasan', 'G1365', 'Aorist of distazō, "to doubt, hesitate, waver." Same verb used of Peter sinking (14:31); describes unsettled faith, not unbelief.', 21),
  (18, 'ἐξουσία', 'exousia', 'G1849', 'Authority, right, jurisdiction. Covers legal, moral, and cosmic dominion. Key word of the chapter: the enthroned Son''s delegated rule over all reality.', 22),
  (18, 'ἐδόθη', 'edothē', 'G1325', 'Aorist passive of didōmi, "to give." Divine passive — the Father has given the Son universal authority, fulfilling Daniel 7:14.', 23),
  (19, 'μαθητεύσατε', 'mathēteusate', 'G3100', 'Aorist imperative of mathēteuō, "to make a disciple." Main verb of the Great Commission — disciple-making is the church''s defining activity.', 24),
  (19, 'ἔθνη', 'ethnē', 'G1484', 'Nations, Gentiles, peoples. Previously largely excluded (10:5-6), now embraced as the scope of mission; fulfills the Abrahamic promise (Gen 12:3).', 25),
  (19, 'βαπτίζοντες', 'baptizontes', 'G907', 'Participle of baptizō, "to immerse, baptize." Initiation rite into the triune Name; the public sign of new-covenant discipleship.', 26),
  (19, 'ὄνομα', 'onoma', 'G3686', 'Name (singular) shared by Father, Son, and Spirit. The single "Name" with three divine persons is the clearest Synoptic statement of trinitarian identity.', 27),
  (20, 'τηρεῖν', 'tērein', 'G5083', 'Present active infinitive of tēreō, "to keep, observe, guard." Discipleship is lifelong keeping of the Lord''s commands, not one-time assent.', 28),
  (20, 'συντελείας', 'synteleias', 'G4930', 'Consummation, completion, end. Used of the end of the age (13:39-40, 49; 24:3); bookends the promise of Christ''s presence across the whole age.', 29),
  (20, 'αἰῶνος', 'aiōnos', 'G165', 'Age, era. The present age in view of the age to come; Christ''s presence extends to the eschatological threshold.', 30)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 28 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

